import{_ as a,o as l,c as o,ai as s}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"macOS IPC","description":"","frontmatter":{"read_when":["编辑 IPC 合约或菜单栏应用 IPC"],"summary":"OpenSoul 应用的 macOS IPC 架构、Gateway 网关节点传输和 PeekabooBridge","title":"macOS IPC","x-i18n":{"generated_at":"2026-02-03T07:52:57Z","model":"claude-opus-4-5","provider":"pi","source_hash":"d0211c334a4a59b71afb29dd7b024778172e529fa618985632d3d11d795ced92","source_path":"platforms/mac/xpc.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/xpc.md","filePath":"zh-CN/platforms/mac/xpc.md","lastUpdated":null}'),i={name:"zh-CN/platforms/mac/xpc.md"};function n(c,e,d,t,r,p){return l(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="opensoul-macos-ipc-架构" tabindex="-1"><a class="header-anchor" href="#opensoul-macos-ipc-架构">#</a> OpenSoul macOS IPC 架构</h1><p><strong>当前模型：</strong> 一个本地 Unix 套接字将<strong>节点主机服务</strong>连接到 <strong>macOS 应用</strong>，用于 exec 审批 + <code>system.run</code>。存在一个 <code>opensoul-mac</code> 调试 CLI 用于发现/连接检查；智能体操作仍通过 Gateway 网关 WebSocket 和 <code>node.invoke</code> 流转。UI 自动化使用 PeekabooBridge。</p><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标">#</a> 目标</h2><ul><li>单个 GUI 应用实例拥有所有面向 TCC 的工作（通知、屏幕录制、麦克风、语音、AppleScript）。</li><li>小型自动化接口：Gateway 网关 + 节点命令，加上用于 UI 自动化的 PeekabooBridge。</li><li>可预测的权限：始终是同一个签名的 bundle ID，由 launchd 启动，因此 TCC 授权保持有效。</li></ul><h2 id="工作原理" tabindex="-1"><a class="header-anchor" href="#工作原理">#</a> 工作原理</h2><h3 id="gateway-网关-节点传输" tabindex="-1"><a class="header-anchor" href="#gateway-网关-节点传输">#</a> Gateway 网关 + 节点传输</h3><ul><li>应用运行 Gateway 网关（本地模式）并作为节点连接到它。</li><li>智能体操作通过 <code>node.invoke</code> 执行（例如 <code>system.run</code>、<code>system.notify</code>、<code>canvas.*</code>）。</li></ul><h3 id="节点服务-应用-ipc" tabindex="-1"><a class="header-anchor" href="#节点服务-应用-ipc">#</a> 节点服务 + 应用 IPC</h3><ul><li>一个无头节点主机服务连接到 Gateway 网关 WebSocket。</li><li><code>system.run</code> 请求通过本地 Unix 套接字转发到 macOS 应用。</li><li>应用在 UI 上下文中执行 exec，必要时提示，并返回输出。</li></ul><p>图示（SCI）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent -&gt; Gateway -&gt; Node Service (WS)</span></span>
<span class="line"><span>                      |  IPC (UDS + token + HMAC + TTL)</span></span>
<span class="line"><span>                      v</span></span>
<span class="line"><span>                  Mac App (UI + TCC + system.run)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="peekaboobridge-ui-自动化" tabindex="-1"><a class="header-anchor" href="#peekaboobridge-ui-自动化">#</a> PeekabooBridge（UI 自动化）</h3><ul><li>UI 自动化使用名为 <code>bridge.sock</code> 的单独 UNIX 套接字和 PeekabooBridge JSON 协议。</li><li>主机优先顺序（客户端侧）：Peekaboo.app → Claude.app → OpenSoul.app → 本地执行。</li><li>安全性：桥接主机需要允许的 TeamID；仅 DEBUG 的同 UID 逃逸通道由 <code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code> 保护（Peekaboo 约定）。</li><li>参见：<a href="/docs/platforms/mac/peekaboo">PeekabooBridge 用法</a>了解详情。</li></ul><h2 id="操作流程" tabindex="-1"><a class="header-anchor" href="#操作流程">#</a> 操作流程</h2><ul><li>重启/重建：<code>SIGN_IDENTITY=&quot;Apple Development: &lt;Developer Name&gt; (&lt;TEAMID&gt;)&quot; scripts/restart-mac.sh</code><ul><li>终止现有实例</li><li>Swift 构建 + 打包</li><li>写入/引导/启动 LaunchAgent</li></ul></li><li>单实例：如果具有相同 bundle ID 的另一个实例正在运行，应用会提前退出。</li></ul><h2 id="加固注意事项" tabindex="-1"><a class="header-anchor" href="#加固注意事项">#</a> 加固注意事项</h2><ul><li>优先要求所有特权接口的 TeamID 匹配。</li><li>PeekabooBridge：<code>PEEKABOO_ALLOW_UNSIGNED_SOCKET_CLIENTS=1</code>（仅 DEBUG）可能允许同 UID 调用者用于本地开发。</li><li>所有通信仅保持本地；不暴露网络套接字。</li><li>TCC 提示仅源自 GUI 应用包；在重建时保持签名的 bundle ID 稳定。</li><li>IPC 加固：套接字模式 <code>0600</code>、令牌、对等 UID 检查、HMAC 质询/响应、短 TTL。</li></ul>`,17)])])}const m=a(i,[["render",n]]);export{u as __pageData,m as default};
